INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9279a6f7-3782-4881-b0ca-27c603c9d9f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solidity: Optimize Gas with Storage vs Memory vs Calldata$escape$,
  $escape$When storing data in Solidity, use `calldata` for function parameters, `memory` for temporary values, and `storage` for persistent data. `calldata` is cheaper because it's read-only and doesn't occupy storage space. `memory` is faster but more expensive than `storage`. Use the `packed` keyword to reduce storage costs by packing structs. Avoid using loops when possible, as they can be expensive. Instead, use array operations or recursion. For example, to iterate over an array, use `for (uint i = 0; i < array.length; i++) ...`. To calculate the sum of an array, use `uint sum = 0; for (uint i = 0; i < array.length; i++) sum += array[i];`$escape$,
  $escape$pragma solidity ^0.8.0;
contract Optimized {
uint[] public array;
function calculateSum() public view returns (uint) {
uint sum = 0;
for (uint i = 0; i < array.length; i++) sum += array[i];
return sum;
}
}$escape$,
  $escape$solidity$escape$,
